cat > /tmp/verify_fix.go << 'EOF'
package main

import (
	"fmt"
	"strings"
	"github.com/goccy/go-yaml"
)

type Child struct {
	Value string `yaml:"value"`
}

type Parent struct {
	Name  string `yaml:"name"`
	Child Child  `yaml:"child"`
}

func main() {
	tests := []struct {
		description  string
		yaml         string
		initialChild Child
		expectedChild Child
	}{
		{
			description:  "Null nested struct preserves default",
			yaml:         "name: test\nchild:\n",
			initialChild: Child{Value: "default1"},
			expectedChild: Child{Value: "default1"},
		},
		{
			description:  "Null nested struct with comments preserves default",
			yaml:         "name: test\nchild:\n  # comment\n",
			initialChild: Child{Value: "default2"},
			expectedChild: Child{Value: "default2"},
		},
		{
			description:  "Provided value overrides default",
			yaml:         "name: test\nchild:\n  value: override\n",
			initialChild: Child{Value: "default3"},
			expectedChild: Child{Value: "override"},
		},
		{
			description:  "Empty map preserves default",
			yaml:         "name: test\nchild: {}\n",
			initialChild: Child{Value: "default4"},
			expectedChild: Child{Value: "default4"},
		},
		{
			description:  "Missing key preserves default",
			yaml:         "name: test\n",
			initialChild: Child{Value: "default5"},
			expectedChild: Child{Value: "default5"},
		},
	}

	allPassed := true
	for _, test := range tests {
		p := Parent{Child: test.initialChild}
		err := yaml.NewDecoder(strings.NewReader(test.yaml)).Decode(&p)
		if err != nil {
			fmt.Printf("❌ %s: %v\n", test.description, err)
			allPassed = false
			continue
		}

		if p.Child.Value != test.expectedChild.Value {
			fmt.Printf("❌ %s: expected %q, got %q\n", test.description, test.expectedChild.Value, p.Child.Value)
			allPassed = false
		} else {
			fmt.Printf("✅ %s\n", test.description)
		}
	}

	if allPassed {
		fmt.Println("\n✅ All tests passed!")
	} else {
		fmt.Println("\n❌ Some tests failed!")
	}
}
EOF
