	"github.com/goccy/go-yaml"
)

type Config struct {
	Name  string `yaml:"name"`
	Value *string `yaml:"value"`
}

func main() {
	// Test 1: Pointer field with default value
	defaultVal := "mydefault"
	c1 := Config{Name: "test", Value: &defaultVal}
	err := yaml.NewDecoder(strings.NewReader("name: test\nvalue:\n  # comment\n")).Decode(&c1)
	if err != nil {
		fmt.Printf("Test 1 failed: %v\n", err)
	} else if c1.Value == nil {
		fmt.Println("❌ Test 1: Pointer was set to nil")
	} else if *c1.Value != "mydefault" {
		fmt.Printf("❌ Test 1: Expected 'mydefault', got '%s'\n", *c1.Value)
	} else {
		fmt.Println("✅ Test 1: Pointer field with default preserved")
	}

	// Test 2: Pointer field with nil default and null value
	c2 := Config{Name: "test", Value: nil}
	err = yaml.NewDecoder(strings.NewReader("name: test\nvalue:\n  # comment\n")).Decode(&c2)
	if err != nil {
		fmt.Printf("Test 2 failed: %v\n", err)
	} else if c2.Value != nil {
		fmt.Printf("❌ Test 2: Expected nil, got %v\n", *c2.Value)
	} else {
		fmt.Println("✅ Test 2: Pointer field with nil default preserved")
