	all_passed = all_passed && testCase(
		"Null nested struct preserves default",
		"app: myapp\nconfig:\n  title: mytitle\n  person:\n    # comment\n",
		NestedConfig{App: "default_app", Config: Config{Title: "default_title", Person: Person{Name: "default_person"}}},
		NestedConfig{App: "myapp", Config: Config{Title: "mytitle", Person: Person{Name: "default_person"}}},
	)

	all_passed = all_passed && testCase(
		"Explicit value overrides default",
		"app: myapp\nconfig:\n  title: mytitle\n  person:\n    name: John\n",
		NestedConfig{App: "default_app", Config: Config{Title: "default_title", Person: Person{Name: "default_person"}}},
		NestedConfig{App: "myapp", Config: Config{Title: "mytitle", Person: Person{Name: "John"}}},
	)

	all_passed = all_passed && testCase(
		"Partially set nested struct preserves missing fields",
		"app: myapp\nconfig:\n  person:\n    name: Jane\n",
		NestedConfig{App: "default_app", Config: Config{Title: "default_title", Person: Person{Name: "default_person"}}},
		NestedConfig{App: "myapp", Config: Config{Title: "default_title", Person: Person{Name: "Jane"}}},
	)

	all_passed = all_passed && testCase(
		"Empty nested struct preserves all defaults",
		"app: myapp\nconfig:\n  person: {}\n",
		NestedConfig{App: "default_app", Config: Config{Title: "default_title", Person: Person{Name: "default_person"}}},
		NestedConfig{App: "myapp", Config: Config{Title: "default_title", Person: Person{Name: "default_person"}}},
	)

	all_passed = all_passed && testCase(
		"Missing nested key preserves defaults",
		"app: myapp\nconfig:\n  title: mytitle\n",
		NestedConfig{App: "default_app", Config: Config{Title: "default_title", Person: Person{Name: "default_person"}}},
		NestedConfig{App: "myapp", Config: Config{Title: "mytitle", Person: Person{Name: "default_person"}}},
	)

	if all_passed {
		fmt.Println("\n✅ All comprehensive tests passed!")
	} else {
		fmt.Println("\n❌ Some tests failed!")
	}
}
